// AUTOGENERATED FROM SCRIPT
export const NOW = new Date();

export function addDays(base: Date, days: number): string {
  const d = new Date(base);
  d.setDate(d.getDate() + days);
  return d.toISOString().split('T')[0];
}
export function subMonths(base: Date, months: number): string {
  const d = new Date(base);
  d.setMonth(d.getMonth() - months);
  return d.toISOString().split('T')[0];
}
export function daysFromNow(dateStr: string): number {
  return Math.ceil((new Date(dateStr).getTime() - NOW.getTime()) / 86400000);
}

export type ExpiryStatus = 'Expired' | 'Critical' | 'Warning' | 'Safe';
export function getStatus(expiryDate: string): ExpiryStatus {
  const d = daysFromNow(expiryDate);
  if (d <= 0) return 'Expired';
  if (d <= 7) return 'Critical';
  if (d <= 180) return 'Warning';
  return 'Safe';
}

