export const BATCH_LIST = BATCHES.map(b => {
  const med = MEDICINES.find(m => m.id === b.medicineId)!;
  const status = getStatus(b.expiryDate);
  const days = daysFromNow(b.expiryDate);
  const lastTest = b.testIntervals[b.testIntervals.length - 1]! || { assay: 100 }; // fallback
  return { ...b, med, status, days, lastTest };
});

export const STATUS_COUNTS = {
  Expired:  BATCH_LIST.filter(b => b.status === 'Expired').length,
  Critical: BATCH_LIST.filter(b => b.status === 'Critical').length,
  Warning:  BATCH_LIST.filter(b => b.status === 'Warning').length,
  Safe:     BATCH_LIST.filter(b => b.status === 'Safe').length,
};

export const expiryDistributionData = [
  { name: 'Expired',  value: STATUS_COUNTS.Expired,  fill: '#ef4444' },
  { name: 'Critical', value: STATUS_COUNTS.Critical, fill: '#dc2626' },
  { name: 'Warning',  value: STATUS_COUNTS.Warning,  fill: '#f59e0b' },
  { name: 'Safe',     value: STATUS_COUNTS.Safe,     fill: '#22c55e' },
];

const mfgCounts: Record<string, number> = {};
BATCH_LIST.forEach(b => {
  const key = b.mfgDate.slice(0, 7);
  mfgCounts[key] = (mfgCounts[key] || 0) + 1;
});
export const manufactureDateData = Object.entries(mfgCounts)
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([month, count]) => ({ month, batches: count }));

const expCounts: Record<string, number> = {};
BATCH_LIST.forEach(b => {
  if (b.days > 0) {
    const key = b.expiryDate.slice(0, 7);
    expCounts[key] = (expCounts[key] || 0) + 1;
  }
});
export const expiryByMonthData = Object.entries(expCounts)
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([month, count]) => ({ month, batches: count }));

export const potencyTrendData = [0, 3, 6, 9, 12].map(month => {
  const row: Record<string, number | string> = { month: `${month}m` };
  MEDICINES.forEach(med => {
    const batches = BATCHES.filter(b => b.medicineId === med.id);
    if(batches.length===0) return;
    const avg = batches.reduce((sum, b) => {
      const t = b.testIntervals.find(ti => ti.month === month);
      return sum + (t?.assay ?? 100);
    }, 0) / batches.length;
    row[med.name.split(' ')[0] || ('M'+med.id)] = +avg.toFixed(2);
  });
  return row;
});

export const testParamData = MEDICINES.map(med => {
  const latestTests = BATCHES.filter(b => b.medicineId === med.id).map(b => b.testIntervals[b.testIntervals.length - 1]!).filter(Boolean);
  if(latestTests.length===0) return { medicine: med.name.split(' ')[0] || ('M'+med.id), Assay:0, Dissolution:0, pH:0, Moisture:0, Impurity:0 };
  const avg = (key: keyof TestInterval) =>
    +(latestTests.reduce((s, t) => s + ((t && t[key] as number) || 0), 0) / latestTests.length).toFixed(2);
  return {
    medicine: med.name.split(' ')[0] || ('M'+med.id),
    Assay: avg('assay'),
    Dissolution: avg('dissolution'),
    pH: avg('pH'),
    Moisture: avg('moisture'),
    Impurity: avg('impurity'),
  };
});

export const passFailData = MEDICINES.map(med => {
  const allTests = BATCHES.filter(b => b.medicineId === med.id)
    .flatMap(b => b.testIntervals).filter(Boolean);
  return {
    medicine: med.name.split(' ')[0] || ('M'+med.id),
    Pass: allTests.filter(t => t.passFail).length,
    Fail: allTests.filter(t => !t.passFail).length,
  };
});

